                    return
                } else {
                    status = "DEPLOYMENT_FAILED"
                    errorMsg = "HTTP $code at end of chain"
                    break
                }
            }
        } catch (e: Exception) {
            status = "DEPLOYMENT_ERROR"
            errorMsg = e.toString()
        }
    }
}

